export type DraftState =
  | { status: "empty" }
  | { status: "open"; id: string; body: string; revisions: number }
  | { status: "published"; id: string; body: string; publishedAt: string };

export type DraftCommand =
  | { type: "open"; id: string }
  | { type: "edit"; body: string }
  | { type: "publish"; at: string };

export type DraftEvent =
  | { type: "DraftOpened"; id: string }
  | { type: "DraftEdited"; body: string }
  | { type: "DraftPublished"; at: string; finalBody: string };

export class DraftError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DraftError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const draftDecider: Decider<DraftCommand, DraftEvent, DraftState> = {
  initialState: { status: "empty" },
  decide(command, state) {
    switch (command.type) {
      case "open":
        if (state.status !== "empty") throw new DraftError("EXISTS");
        return [{ type: "DraftOpened", id: command.id }];
      case "edit":
        if (state.status === "published") throw new DraftError("PUBLISHED");
        if (state.status !== "open") throw new DraftError("NOT_OPEN");
        return [{ type: "DraftEdited", body: command.body }];
      case "publish":
        if (state.status !== "open") throw new DraftError("NOT_OPEN");
        if (state.body.length === 0) throw new DraftError("EMPTY");
        return [{ type: "DraftPublished", at: command.at, finalBody: state.body }];
      default:
        throw new DraftError("UNKNOWN");
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "DraftOpened":
        return { status: "open", id: event.id, body: "", revisions: 0 };
      case "DraftEdited":
        if (state.status !== "open") return state;
        return { ...state, body: event.body, revisions: state.revisions + 1 };
      case "DraftPublished":
        if (state.status !== "open") return state;
        return { status: "published", id: state.id, body: event.finalBody, publishedAt: event.at };
      default: {
        const _n: never = event;
        return state;
      }
    }
  },
};
```

A Decider is a pure triple of initialState, decide(command, state) returning events, and evolve(state, event) returning the next state. No IO. Commands either emit events or throw domain errors; events are the source of truth.

