export type DocEvent =
  | { type: "DocumentCreated"; id: string; title: string }
  | { type: "DocumentSubmitted"; id: string; at: string }
  | { type: "DocumentApproved"; id: string; at: string }
  | { type: "DocumentArchived"; id: string };

export interface DocStatsView {
  readonly drafting: number;
  readonly submitted: number;
  readonly approved: number;
  readonly perDoc: Readonly<Record<string, "drafting" | "submitted" | "approved">>;
}

export const emptyView: DocStatsView = { drafting: 0, submitted: 0, approved: 0, perDoc: {} };

export function project(view: DocStatsView, event: DocEvent): DocStatsView {
  switch (event.type) {
    case "DocumentCreated":
      return {
        ...view,
        drafting: view.drafting + 1,
        perDoc: { ...view.perDoc, [event.id]: "drafting" },
      };
    case "DocumentSubmitted": {
      const prev = view.perDoc[event.id];
      if (prev !== "drafting") return view;
      return {
        ...view,
        drafting: view.drafting - 1,
        submitted: view.submitted + 1,
        perDoc: { ...view.perDoc, [event.id]: "submitted" },
      };
    }
    case "DocumentApproved": {
      const prev = view.perDoc[event.id];
      if (prev !== "submitted") return view;
      return {
        ...view,
        submitted: view.submitted - 1,
        approved: view.approved + 1,
        perDoc: { ...view.perDoc, [event.id]: "approved" },
      };
    }
    case "DocumentArchived":
      return view;
    default: {
      const _n: never = event;
      return view;
    }
  }
}

export function rebuildStats(events: DocEvent[]): DocStatsView {
  return events.reduce(project, emptyView);
}
