export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> { readonly version: number; readonly state: S; }

interface DocV1 { id: string; status: "open" | "closed"; }
interface DocV2 { id: string; status: "drafting" | "approved"; approvedAt?: string; }
export interface DocumentCurrent {
  readonly id: string;
  readonly status: "drafting" | "submitted" | "approved";
  readonly approvedAt: string | null;
  readonly submittedAt: string | null;
}

function v1Tov2(s: DocV1): DocV2 {
  return { id: s.id, status: s.status === "closed" ? "approved" : "drafting", approvedAt: undefined };
}

function v2Tov3(s: DocV2): DocumentCurrent {
  return {
    id: s.id,
    status: s.status,
    approvedAt: s.approvedAt ?? null,
    submittedAt: null,
  };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<DocumentCurrent> {
  let version = snap.version;
  let state: unknown = snap.state;
  if (version === 1) { state = v1Tov2(state as DocV1); version = 2; }
  if (version === 2) { state = v2Tov3(state as DocV2); version = 3; }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION:${version}`);
  const current = state as DocumentCurrent;
  return { version: CURRENT_VERSION, state: current };
}

export function loadSnapshot(raw: { version: number; state: unknown }): DocumentCurrent {
  return upgradeSnapshot(raw).state;
}
