export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> { readonly event: E; readonly revision: bigint; }

export interface AppendOptions { expectedRevision: ExpectedRevision; }
export interface AppendOutcome { kind: "ok"; nextRevision: bigint; }
export interface AppendConflict { kind: "conflict"; actualRevision: bigint | null; }

export interface EventStore<E> {
  readStream(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream(stream: string, events: E[], opts: AppendOptions): Promise<AppendOutcome | AppendConflict>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly expected: ExpectedRevision, public readonly actual: bigint | null) {
    super("CONCURRENCY_CONFLICT");
