export type SignatoryEvent =
  | { type: "SignatoryRegistered"; id: string; name: string }
  | { type: "SignatoryRoleChanged"; role: string }
  | { type: "SignatoryDeactivated"; at: string };

export type SignatoryState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; role: string }
  | { status: "inactive"; id: string; name: string; role: string; deactivatedAt: string };

export function when(state: SignatoryState, event: SignatoryEvent): SignatoryState {
  switch (event.type) {
    case "SignatoryRegistered":
      return { status: "active", id: event.id, name: event.name, role: "member" };
    case "SignatoryRoleChanged":
      if (state.status === "none") return state;
      return { ...state, role: event.role };
    case "SignatoryDeactivated":
      if (state.status !== "active") return state;
      return { status: "inactive", id: state.id, name: state.name, role: state.role, deactivatedAt: event.at };
    default: { const _n: never = event; return state; }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>, reducer: (s: S, e: E) => S, initial: S,
): Promise<S> {
  let acc = initial;
  for await (const e of stream) acc = reducer(acc, e);
  return acc;
}

export async function loadSignatory(stream: AsyncIterable<SignatoryEvent>): Promise<SignatoryState> {
  return aggregateStream<SignatoryState, SignatoryEvent>(stream, when, { status: "none" });
}
